import{_ as i,o as e,c as s,a2 as l}from"./chunks/framework.BKG_UbFK.js";const u=JSON.parse('{"title":"पब्लिशिंग","description":"","frontmatter":{},"headers":[],"relativePath":"hi/guide/publishing.md","filePath":"hi/guide/publishing.md"}'),t={name:"hi/guide/publishing.md"};function n(o,a,h,c,r,d){return e(),s("div",null,[...a[0]||(a[0]=[l(`<h1 id="पब्लिशिंग" tabindex="-1">पब्लिशिंग <a class="header-anchor" href="#पब्लिशिंग" aria-label="Permalink to &quot;पब्लिशिंग&quot;">​</a></h1><p>Clearance <code>vendor:publish</code> tags के माध्यम से तीन प्रकार के एसेट publish करता है: config, migrations, और translations। Config और migrations installer द्वारा स्वचालित रूप से संभाले जाते हैं (देखें <a href="/clearance-docs/hi/guide/installation.html">इंस्टॉलेशन</a>); यह पेज इन्हें मैन्युअल रूप से publish करने, और translations को publish करने को कवर करता है।</p><h2 id="config" tabindex="-1">Config <a class="header-anchor" href="#config" aria-label="Permalink to &quot;Config&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vendor:publish</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tag=clearance-config</span></span></code></pre></div><p><code>config/clearance.php</code> को आपके एप्लिकेशन में publish करता है। हर key, उसके डिफ़ॉल्ट, और उसके उद्देश्य के लिए देखें <a href="/clearance-docs/hi/guide/configuration.html">कॉन्फ़िगरेशन संदर्भ</a>।</p><h2 id="translations" tabindex="-1">Translations <a class="header-anchor" href="#translations" aria-label="Permalink to &quot;Translations&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vendor:publish</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tag=clearance-translations</span></span></code></pre></div><p>यह 9 बंडल की गई भाषाओं (<code>ar</code>, <code>en</code>, <code>es</code>, <code>fr</code>, <code>hi</code>, <code>it</code>, <code>pt</code>, <code>ru</code>, <code>zh</code>) को आपके ऐप में <code>lang/vendor/clearance/{locale}/ui.php</code> में कॉपी करता है। किसी नई locale को जोड़ने या किसी मौजूदा locale में strings को override करने के लिए, वहां एक locale directory जोड़ें, canonical key संदर्भ के रूप में <code>en/ui.php</code> का उपयोग करते हुए। सभी locales एक समान key सेट expose करती हैं, जिसे हर बदलाव पर एक समर्पित टेस्ट द्वारा verify किया जाता है।</p><h2 id="पैनल-layout-को-override-करना" tabindex="-1">पैनल Layout को override करना <a class="header-anchor" href="#पैनल-layout-को-override-करना" aria-label="Permalink to &quot;पैनल Layout को override करना&quot;">​</a></h2><p><code>layout</code> config key यह नियंत्रित करता है कि पूरे पेज वाले components किस Blade layout का उपयोग करते हैं:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// config/clearance.php</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;layout&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> null</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// host app&#39;s default (config(&#39;livewire.layout&#39;))</span></span></code></pre></div><p>अपने एप्लिकेशन के डिफ़ॉल्ट Livewire layout का उपयोग करने के लिए इसे <code>null</code> छोड़ दें, या पैनल को किसी कस्टम shell के भीतर रेंडर करने के लिए इसे किसी विशिष्ट layout view पर सेट करें।</p><h2 id="migrations" tabindex="-1">Migrations <a class="header-anchor" href="#migrations" aria-label="Permalink to &quot;Migrations&quot;">​</a></h2><p>Clearance के migrations <code>php artisan clearance:install</code> द्वारा स्वचालित रूप से publish और run किए जाते हैं - यदि <code>roles</code> टेबल अभी तक मौजूद नहीं है तो installer पहले Spatie के migrations को भी publish और run करता है। पूरे चरण-दर-चरण फ्लो के लिए देखें <a href="/clearance-docs/hi/guide/installation.html">इंस्टॉलेशन</a>, और किसी नए (fresh) सेटअप पर कभी सादा <code>migrate</code> न चलाने के बारे में <a href="/clearance-docs/hi/guide/installation.html#run-the-installer">danger callout</a> देखें।</p><h2 id="संबंधित" tabindex="-1">संबंधित <a class="header-anchor" href="#संबंधित" aria-label="Permalink to &quot;संबंधित&quot;">​</a></h2><ul><li><a href="/clearance-docs/hi/guide/configuration.html">कॉन्फ़िगरेशन संदर्भ</a> - हर config key</li><li><a href="/clearance-docs/hi/guide/installation.html">इंस्टॉलेशन</a> - पूरा installer फ्लो</li><li><a href="/clearance-docs/hi/guide/migration.html">माइग्रेशन</a> - मौजूदा Spatie installs के लिए <code>clearance:backfill</code></li></ul>`,16)])])}const g=i(t,[["render",n]]);export{u as __pageData,g as default};
